package com.interview.incidentrca.config;
import com.interview.incidentrca.entity.*;import com.interview.incidentrca.enums.*;import com.interview.incidentrca.repository.*;import lombok.RequiredArgsConstructor;import org.springframework.boot.CommandLineRunner;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.security.crypto.password.PasswordEncoder;import java.time.Instant;
@Configuration @RequiredArgsConstructor public class DataSeeder{private final UserRepository users;private final ServiceComponentRepository services;private final IncidentRepository incidents;private final IncidentCommentRepository comments;private final IncidentStatusHistoryRepository histories;private final AuditLogRepository audits;private final PasswordEncoder encoder;
 @Bean CommandLineRunner seed(){return args->{if(users.count()>0)return;User admin=users.save(User.builder().name("Admin User").email("admin@incidentrca.dev").password(encoder.encode("Admin@123")).role(Role.ADMIN).createdAt(Instant.now()).build());User eng=users.save(User.builder().name("Priya Engineer").email("engineer@incidentrca.dev").password(encoder.encode("Engineer@123")).role(Role.ENGINEER).createdAt(Instant.now()).build());users.save(User.builder().name("Viewer User").email("viewer@incidentrca.dev").password(encoder.encode("Viewer@123")).role(Role.VIEWER).createdAt(Instant.now()).build());ServiceComponent pay=services.save(ServiceComponent.builder().name("Payment Gateway").ownerTeam("Digital Ops").businessCriticality("CRITICAL").createdAt(Instant.now()).build());ServiceComponent auth=services.save(ServiceComponent.builder().name("Identity Service").ownerTeam("IAM Platform").businessCriticality("HIGH").createdAt(Instant.now()).build());Incident i1=incidents.save(Incident.builder().title("Payment API returning 503 after release").description("External gateway calls timing out after deployment. Users see checkout failure.").severity(Severity.CRITICAL).status(IncidentStatus.INVESTIGATING).serviceComponent(pay).assignedEngineer(eng).createdBy(admin).createdAt(Instant.now().minusSeconds(1800)).updatedAt(Instant.now()).build());Incident i2=incidents.save(Incident.builder().title("Login token validation failing").description("JWT validation unauthorized errors for multiple users in APAC region.").severity(Severity.HIGH).status(IncidentStatus.OPEN).serviceComponent(auth).assignedEngineer(eng).createdBy(admin).createdAt(Instant.now().minusSeconds(3600)).updatedAt(Instant.now()).build());comments.save(IncidentComment.builder().incident(i1).author(eng).message("Checked logs, failures started after 10:30 deployment.").createdAt(Instant.now().minusSeconds(900)).build());histories.save(IncidentStatusHistory.builder().incident(i1).toStatus(IncidentStatus.OPEN).changedBy(admin).note("Seed incident created").changedAt(i1.getCreatedAt()).build());histories.save(IncidentStatusHistory.builder().incident(i1).fromStatus(IncidentStatus.OPEN).toStatus(IncidentStatus.INVESTIGATING).changedBy(eng).note("Engineer started investigation").changedAt(Instant.now().minusSeconds(1200)).build());audits.save(AuditLog.builder().actor(admin).action("INCIDENT_CREATED").details("Seeded enterprise demo incidents").timestamp(Instant.now()).build());};}}
